USE LIVE
GO

DROP TABLE #T1
SELECT OB.WORKORDER_TYPE
	, OB.WORKORDER_BASE_ID
	, OB.WORKORDER_LOT_ID
	, OB.WORKORDER_SPLIT_ID
	, OB.WORKORDER_SUB_ID
	, OB.SEQUENCE_NO
	, O.RESOURCE_ID
	, O.OPERATION_TYPE
	, O.[STATUS]
	, CAST(CAST(OB.BITS AS VARBINARY(MAX)) AS NVARCHAR(MAX)) AS [BEFORE_OB]
	, REPLACE(CAST(CAST(OB.BITS AS VARBINARY(MAX)) AS NVARCHAR(MAX)) 
		, 'INDICATE MASKANT USED:  PLUGS / TAPE / LIQUID'
		, 'MASKANT USED: PLUGS'
	) AS [AFTER_OB]
	, OB.BITS AS [OB_BINARY]
	, OB.BITS_LENGTH AS [OB_BITLEN]
INTO #T1
FROM OPERATION O
INNER JOIN OPERATION_BINARY OB
	ON O.WORKORDER_TYPE = OB.WORKORDER_TYPE
	AND O.WORKORDER_BASE_ID = OB.WORKORDER_BASE_ID
	AND O.WORKORDER_LOT_ID = OB.WORKORDER_LOT_ID
	AND O.WORKORDER_SPLIT_ID = OB.WORKORDER_SPLIT_ID
	AND O.WORKORDER_SUB_ID = OB.WORKORDER_SUB_ID
	AND O.SEQUENCE_NO = OB.SEQUENCE_NO
WHERE (O.WORKORDER_TYPE = 'M')
	AND RESOURCE_ID = 'P1F1-PEN-MASK'
	AND CAST(CAST(OB.BITS AS VARBINARY(MAX)) AS NVARCHAR(MAX)) LIKE '%INDICATE MASKANT USED:  PLUGS / TAPE / LIQUID%'
	AND OB.WORKORDER_BASE_ID IN ('60P5773201M009', '60P5773202M006', '633Z2307-9003', '633Z2307-9004', '633Z6302-9003', '65-50850-14', '65-54994Y16', '65B10990-14', '65B10990-15', '06ND71116-10', '06ND71116-11', '06ND71637-2', '06ND78033-31', '06ND78033-32', '06ND78033-32', '100T1507-111', '100T1507-116', '100T1507-120', '115A3757-937', '412A7220-27B', '412A7220-41B', '412A7220-70B', '412A7220-78B', '412A7220-81B', '412A7220-9B', '412A7230-231B', '412A7230-232B', '412A7230-33B', '412U2508-124', '412U2508-125', '412U2508-66', '412U2508-69', '412U2508-73', '412U2508-74', '412U2508-77', '412U2508-87', '412U2508-88', '412U2508-92', '412U2508-93', '412U2508-95', '412U2508-96', '412U2508-99', '69B11462-19', '145T8847-5', '145W5832-27', '146A7763-64', '146A7763-67', '146A7763-69', '146A7763-73', '112U1755-1', '112U1755-2', '715Z8562-2', '112U2713-4', '112U2744-10', '112U2744-9', '112U2748-9', '112U2762-10', '115U2112-906', '115U2121-18', '115U2219-15', '115U3212-90010', '115U4210-21MOD', '115U4210-23MOD', '115U4210-24MOD', '115U9139-901', '146W4645-505', '148A7407-44', '149A8017-2', '149U7251-3', '149U7285-17', '149U7285-18', '152W6597-10', '257T3213-1', '112U2765-10', '112U7652-8', '112W2360-45', '112W2361-42', '251A2346-2', '433W5201-33', '433W5218-16B', '439T5300-119', '472W2106-10', '472W2106-14', '775-34513-121', '113T1337-17', '113U1291-3', '113U1291-4', '140T0123-4', '152W7480-4', '152W7480-6', '17P2A3476-513', '17P2A3476-516', '17P2A6040-3', '213U3120-1', '213W3131-8', '215Z5114-2', '293U3654-3', '293U3654-4', '313N3056-6', '412U2702-320', '412U2702-328', '412U2702-332', '412U2702-332', '412U2702-338', '412U2702-350', '412U2702-352', '412U2702-355', '412U2702-366', '412U2702-370', '412U2702-376', '412U2702-381', '413U1165-508', '413U1165-523', '413U1165-524', '413U1165-527', '413U1165-528', '413U1235-193', '492Z1204-7', '492Z1204-8', '492Z3109-10', '140W9621-12', '140W9621-16', '141W1156-1', '141W1156-3', '142A6285-24', '142A6301-9003', '142A6332-3', '142A6332-6', '14